VALUES
(
    'Obrigacao',
    'Determinação, após o trânsito em julgado, à autoridade responsável pelo Instituto de Previdência Municipal dos Servidores Públicos Municipais de Messias Targino, para que, no prazo de 60 dias úteis, de acordo com o inteiro teor desta Decisão, adote as providências: excluir do ato aposentador as menções ao artigo 40, § 1º, II, da CF/88; ao artigo 63, da Lei Municipal nº 591/2017 e ao artigo 6º da Emenda Constitucional nº 41/2003; fazer cessar o reajuste, do vencimento básico da parte interessada, sem fundamento legal, adequando a concessão dos proventos ao quanto prescrito nas Súmulas Vinculantes nº 4, nº 15 e nº 16, todas do Supremo Tribunal Federal; inserir no Sistema Legis-TCE/RN toda a legislação correlata à fixação do vencimento básico e demais reajustes remuneratórios referentes ao cargo da parte interessada; retificar o SIAI-DP, a fim de que o contracheque da parte interessada passe a constar na aba remuneração de servidores e não na parte a que se destina aos pensionistas.',
    1,
    NULL,
    NULL,
    539247,
    NULL,
    'Provisorio',
    NULL,
    'IPSMTARGIN',
    '05911205424',
    '2026-03-26 13:32:28',
